// ============================================================
// PARSE INPUT + SECURITY + CONFIG + STATE MANAGEMENT
// v2.1 — IDs Notion corrigés + Health Tracking
// ============================================================

// --- CONFIGURATION CORRIGÉE ---
const CFG = {
  CHAT_ID: 8572640484,
  TZ: 'Europe/Paris',

  // === IDs NOTION CORRECTS ===
  NOTION_PROJETS_DB:   '2f9f514e-a66d-81bf-a380-000b30acba41',
  NOTION_OBJECTIFS_DB: '2f9f514e-a66d-8148-9b4f-000beaef81b4',
  NOTION_VICTOIRES_DB: '2f9f514e-a66d-816d-8457-000bf6152991',
  NOTION_SANTE_LOG_DB: '2f9f514e-a66d-814f-9909-000b66929316',
  NOTION_TACHES_DB:    '9412b135-63fa-4b57-9ee6-19bf063f6bd9',
  NOTION_REFLEXIONS_DB:'2f9f514e-a66d-81f4-8800-000bd1cac7d5',

  COLORS: {
    'H1-Pro':        { id: '11', emoji: '🔴', label: '[PRO]',        horizon: '⚫ H1 Socle' },
    'H1-Admin':      { id: '8',  emoji: '⚫', label: '[ADMIN]',      horizon: '⚫ H1 Socle' },
    'H1-Santé':      { id: '2',  emoji: '🟢', label: '[SANTÉ]',      horizon: '⚫ H1 Socle' },
    'H1-Famille':    { id: '5',  emoji: '🟡', label: '[FAMILLE]',    horizon: '⚫ H1 Socle' },
    'H2-Croissance': { id: '9',  emoji: '🔵', label: '[CROISSANCE]', horizon: '🔵 H2 Croissance' },
    'H3-Passion':    { id: '3',  emoji: '🟣', label: '[PASSION]',    horizon: '🟣 H3 Passion' },
  },
  COLOR_TO_KEY: { '11':'H1-Pro','8':'H1-Admin','2':'H1-Santé','5':'H1-Famille','9':'H2-Croissance','3':'H3-Passion' },

  POINTS: {
    'objectif': 10, 'progres': 5, 'difficile': 7, 'insight': 3, 'milestone': 15
  },
  POINTS_LABELS: {
    'objectif':  '🎯 Objectif terminé',
    'progres':   '📈 Progrès significatif',
    'difficile': '🔥 Action difficile',
    'insight':   '💡 Insight',
    'milestone': '🏆 Milestone'
  },

  SAISON: {
    nom: 'Saison 1 (Fév-Mars 2026)',
    debut: '2026-02-03',
    fin: '2026-03-16'
  },

  AUTO_HORIZON: {
    'sante':      'H1-Santé',
    'admin':      'H1-Admin',
    'famille':    'H1-Famille',
    'travail':    'H1-Pro',
    'projet':     null,
    'loisir':     'H3-Passion'
  }
};

// --- PARSE INPUT ---
const update = $input.first().json;
let chatId, text, callbackData, callbackMessageId, firstName;

if (update.message) {
  chatId = update.message.chat.id;
  text = (update.message.text || '').trim();
  firstName = update.message.from.first_name || '';
} else if (update.callback_query) {
  chatId = update.callback_query.message.chat.id;
  callbackData = update.callback_query.data;
  callbackMessageId = update.callback_query.message.message_id;
  firstName = update.callback_query.from.first_name || '';
  text = '';
}

// --- SECURITY CHECK ---
if (chatId !== CFG.CHAT_ID) {
  return [{ json: { route: 'silent' } }];
}

// --- STATE MANAGEMENT ---
const state = $getWorkflowStaticData('global');
const now = new Date().toISOString();

for (const [id, s] of Object.entries(state)) {
  if (s && s.expires_at && s.expires_at < now) delete state[id];
}

const chatState = state[String(chatId)];

function setState(cmd, step, data = {}) {
  const exp = new Date(Date.now() + 3600000).toISOString();
  state[String(chatId)] = {
    command: cmd, step, data,
    updated_at: now, expires_at: exp
  };
}

function clearState() {
  delete state[String(chatId)];
}

function getState() {
  return state[String(chatId)] || null;
}

function todayStr() {
  const d = new Date();
  return d.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: CFG.TZ });
}

function makeButtons(rows) {
  return JSON.stringify({ inline_keyboard: rows });
}

// --- ROUTING LOGIC ---
let route = 'silent';
let output = { chatId: String(chatId), cfg: CFG };

if (callbackData) {
  route = 'callback';
  output.callbackData = callbackData;
  output.callbackMessageId = callbackMessageId;
  output.chatState = getState();

} else if (text.startsWith('/')) {
  clearState();
  const parts = text.split(/\s+/);
  const cmd = parts[0].toLowerCase().replace('@.*', '');
  const args = parts.slice(1).join(' ');

  switch(cmd) {
    case '/aide': case '/help': case '/start':
      route = 'aide'; break;
    case '/jour': case '/j':
      route = 'jour'; break;
    case '/event': case '/e':
      route = 'event_init'; break;
    case '/audit': case '/a':
      route = 'audit_init'; break;
    case '/sport': case '/s':
      route = 'sport'; output.args = args; break;
    case '/poids': case '/p':
      route = 'poids'; output.args = args; break;
    case '/eau':
      route = 'eau'; output.args = args; break;
    case '/victoire': case '/v':
      route = 'victoire_init'; output.args = args; break;
    case '/bilan': case '/b':
      route = 'bilan'; break;
    default:
      route = 'unknown'; output.text = cmd;
  }

} else if (chatState && chatState.command) {
  route = 'state_continue';
  output.freeText = text;
  output.chatState = getState();

} else {
  route = 'unknown_text';
}

output.route = route;
output.firstName = firstName;

return [{ json: output }];

// === FORMAT /jour ===
const events = $input.all().map(i => i.json).filter(e => e && e.id);
const chatId = $('Parse & Route').first().json.chatId;
const CFG = $('Parse & Route').first().json.cfg;

const dateStr = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long', day: 'numeric', month: 'long',
  timeZone: 'Europe/Paris'
});

const groups = { 'H1': [], 'H2': [], 'H3': [], 'other': [] };

for (const ev of events) {
  const colorId = ev.colorId || '0';
  const key = CFG.COLOR_TO_KEY[colorId];

  let startTime = '';
  if (ev.start && ev.start.dateTime) {
    startTime = new Date(ev.start.dateTime).toLocaleTimeString('fr-FR', {
      hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris'
    });
  }

  const emoji = key ? CFG.COLORS[key].emoji : '📅';
  const duration = ev.start?.dateTime && ev.end?.dateTime
    ? Math.round((new Date(ev.end.dateTime) - new Date(ev.start.dateTime)) / 60000)
    : 0;
  const durStr = duration >= 60 ? `${Math.floor(duration/60)}h${duration%60 > 0 ? duration%60 : ''}` : `${duration} min`;

  const item = {
    time: startTime,
    text: `${startTime} ${emoji} ${ev.summary || 'Sans titre'} (${durStr})`,
    colorId, key, id: ev.id,
    description: ev.description || '',
    summary: ev.summary || ''
  };

  if (key === 'H2-Croissance' && ev.description) {
    const ddfMatch = ev.description.match(/DDF\s*:\s*(.+)/i);
    if (ddfMatch) item.text += `\n  └ 📌 DDF : ${ddfMatch[1].trim()}`;
  }

  if (key && key.startsWith('H1')) groups.H1.push(item);
  else if (key && key.startsWith('H2')) groups.H2.push(item);
  else if (key && key.startsWith('H3')) groups.H3.push(item);
  else groups.other.push(item);
}

let msg = `📅 <b>AGENDA — ${dateStr}</b>\n`;

if (groups.H1.length) {
  msg += `\n⚫ <b>H1 - SOCLE</b>\n`;
  groups.H1.forEach(e => { msg += `  ${e.text}\n`; });
}
if (groups.H2.length) {
  msg += `\n🔵 <b>H2 - CROISSANCE</b>\n`;
  groups.H2.forEach(e => { msg += `  ${e.text}\n`; });
}
if (groups.H3.length) {
  msg += `\n🟣 <b>H3 - PASSION</b>\n`;
  groups.H3.forEach(e => { msg += `  ${e.text}\n`; });
}
if (groups.other.length) {
  msg += `\n📅 <b>AUTRES</b>\n`;
  groups.other.forEach(e => { msg += `  ${e.text}\n`; });
}

if (!events.length) {
  msg += `\n✨ Journée libre ! Profites-en pour avancer sur un bloc 🔵 H2.`;
}

msg += `\n━━━━━━━━━━━━━`;

const buttons = [];
const h2Events = [...groups.H2];
for (const ev of h2Events) {
  buttons.push([
    { text: `✅ ${ev.summary.substring(0, 20)}`, callback_data: `done|${ev.id}` },
    { text: '📋 Décomposer', callback_data: `decompose|${ev.id}|${ev.summary}` }
  ]);
}

const replyMarkup = buttons.length
  ? JSON.stringify({ inline_keyboard: buttons })
  : undefined;

return [{ json: { chatId, text: msg, parse_mode: 'HTML', replyMarkup } }];

// === INIT /event (conversationnel) ===
const chatId = $input.first().json.chatId;
const state = $getWorkflowStaticData('global');

state[String(chatId)] = {
  command: 'event',
  step: 'ask_horizon',
  data: {},
  updated_at: new Date().toISOString(),
  expires_at: new Date(Date.now() + 3600000).toISOString()
};

const text = '🎯 <b>Créons un événement !</b>\n\nQuel horizon ?';

const replyMarkup = JSON.stringify({
  inline_keyboard: [
    [
      { text: '🔴 H1-Pro', callback_data: 'event_hz|H1-Pro' },
      { text: '⚫ H1-Admin', callback_data: 'event_hz|H1-Admin' },
      { text: '🟢 H1-Santé', callback_data: 'event_hz|H1-Santé' }
    ],
    [
      { text: '🟡 H1-Famille', callback_data: 'event_hz|H1-Famille' },
      { text: '🔵 H2-Croissance', callback_data: 'event_hz|H2-Croissance' },
      { text: '🟣 H3-Passion', callback_data: 'event_hz|H3-Passion' }
    ]
  ]
});

return [{ json: { chatId, text, parse_mode: 'HTML', replyMarkup } }];

// === INIT /audit (conversationnel) ===
const chatId = $input.first().json.chatId;
const state = $getWorkflowStaticData('global');

state[String(chatId)] = {
  command: 'audit',
  step: 'ask_activity',
  data: {},
  updated_at: new Date().toISOString(),
  expires_at: new Date(Date.now() + 3600000).toISOString()
};

const text = '📋 <b>AUDIT D\'ACTIVITÉ</b>\n\nQuelle activité veux-tu auditer ?';

return [{ json: { chatId, text, parse_mode: 'HTML' } }];

// === /sport [min] — CORRIGÉ v2.1 ===
// Écrit dans Santé Log ET crée une Victoire
const input = $input.first().json;
const chatId = input.chatId;
const args = input.args;
const minutes = parseInt(args);

if (!minutes || isNaN(minutes) || minutes <= 0) {
  return [{ json: {
    chatId, parse_mode: 'HTML',
    text: '⚠️ Usage : <code>/sport 45</code> (minutes)',
    healthLog: null,
    victoire: null
  }}];
}

const today = new Date().toISOString().split('T')[0];
const text = `💪 <b>Sport logué : ${minutes} min</b>\n📅 ${new Date().toLocaleDateString('fr-FR', {timeZone:'Europe/Paris'})}\n🏆 +5 points (progrès)\n✅ Santé Log + Victoire enregistrés`;

return [{ json: {
  chatId, text, parse_mode: 'HTML',
  // Données pour Santé Log
  healthLog: {
    nom: `Sport ${minutes} min`,
    date: today,
    metrique: 'Sport',
    valeur: minutes,
    unite: 'min',
    detail: ''
  },
  // Données pour Victoire
  victoire: {
    title: `💪 Sport ${minutes} min`,
    type: '📈 Progrès significatif',
    horizon: '⚫ H1 Socle',
    points: 5,
    saison: 'Saison 1 (Fév-Mars 2026)'
  }
}}];

// === /poids [kg] — CORRIGÉ v2.1 ===
// Écrit dans Santé Log
const input = $input.first().json;
const chatId = input.chatId;
const args = input.args;
const poids = parseFloat(args.replace(',', '.'));

if (!poids || isNaN(poids) || poids < 30 || poids > 300) {
  return [{ json: {
    chatId, parse_mode: 'HTML',
    text: '⚠️ Usage : <code>/poids 82.3</code> (kg)',
    healthLog: null
  }}];
}

const today = new Date().toISOString().split('T')[0];
const text = `⚖️ <b>Poids logué : ${poids} kg</b>\n📅 ${new Date().toLocaleDateString('fr-FR', {timeZone:'Europe/Paris'})}\n✅ Santé Log mis à jour`;

return [{ json: {
  chatId, text, parse_mode: 'HTML',
  healthLog: {
    nom: `Poids ${poids} kg`,
    date: today,
    metrique: 'Poids',
    valeur: poids,
    unite: 'kg',
    detail: ''
  }
}}];

// === /eau [L] — AVEC CUMUL DEPUIS NOTION ===

// Récupérer les données d'entrée
const allItems = $input.all();

// Les données du Parse & Route
let chatId, args;
try {
  const parseData = $('Parse & Route').first().json;
  chatId = parseData.chatId;
  args = parseData.args;
} catch(e) {
  chatId = '8572640484';
  args = '';
}

const litres = parseFloat((args || '').replace(',', '.'));

if (!litres || isNaN(litres) || litres <= 0 || litres > 5) {
  return [{ json: {
    chatId, parse_mode: 'HTML',
    text: '⚠️ Usage : <code>/eau 0.5</code> (litres)',
    healthLog: null
  }}];
}

// Calculer le cumul depuis les données Notion récupérées
let cumulExistant = 0;
for (const item of allItems) {
  // Format Notion API standard
  if (item.json && item.json.properties && item.json.properties.Valeur) {
    const valeur = item.json.properties.Valeur.number;
    if (valeur && !isNaN(valeur)) {
      cumulExistant += valeur;
    }
  }
  // Format simplifié n8n
  if (item.json && typeof item.json.Valeur === 'number') {
    cumulExistant += item.json.Valeur;
  }
}

// Nouveau total = cumul existant + nouvelle entrée
const nouveauTotal = Math.round((cumulExistant + litres) * 10) / 10;
const objectif = 2.5;
const pct = Math.min(100, Math.round((nouveauTotal / objectif) * 100));
const barFull = Math.round(pct / 10);
const barEmpty = 10 - barFull;
const bar = '█'.repeat(barFull) + '░'.repeat(barEmpty);

const today = new Date().toISOString().split('T')[0];
const text = `💧 <b>+${litres}L logué</b>\n📊 Total aujourd'hui : ${nouveauTotal}L / ${objectif}L\n${bar} ${pct}%\n✅ Santé Log mis à jour`;

return [{ json: {
  chatId, text, parse_mode: 'HTML',
  healthLog: {
    nom: `Eau +${litres}L (total: ${nouveauTotal}L)`,
    date: today,
    metrique: 'Eau',
    valeur: litres,
    unite: 'L',
    detail: `Cumul jour: ${nouveauTotal}L`
  }
}}];

// === INIT /victoire (conversationnel) ===
const input = $input.first().json;
const chatId = input.chatId;
const args = input.args;
const state = $getWorkflowStaticData('global');

if (!args) {
  return [{ json: {
    chatId, parse_mode: 'HTML',
    text: '⚠️ Usage : <code>/victoire Page pricing terminée !</code>'
  }}];
}

state[String(chatId)] = {
  command: 'victoire',
  step: 'ask_type',
  data: { title: args },
  updated_at: new Date().toISOString(),
  expires_at: new Date(Date.now() + 3600000).toISOString()
};

const text = `🏆 <b>VICTOIRE !</b>\n"${args}"\n\nQuel type ?`;

const replyMarkup = JSON.stringify({
  inline_keyboard: [
    [{ text: '🎯 Objectif terminé (10pts)', callback_data: 'vic_type|objectif' }],
    [{ text: '📈 Progrès (5pts)', callback_data: 'vic_type|progres' }],
    [{ text: '🔥 Action difficile (7pts)', callback_data: 'vic_type|difficile' }],
    [{ text: '💡 Insight (3pts)', callback_data: 'vic_type|insight' }],
    [{ text: '🏆 Milestone (15pts)', callback_data: 'vic_type|milestone' }]
  ]
});

return [{ json: { chatId, text, parse_mode: 'HTML', replyMarkup } }];

// === FORMAT /bilan ===
const events = $input.all().map(i => i.json).filter(e => e && e.id);
const chatId = $('Parse & Route').first().json.chatId;
const CFG = $('Parse & Route').first().json.cfg;
const state = $getWorkflowStaticData('global');

const weekBlocks = [];
let blockIndex = 1;

for (const ev of events) {
  const colorId = ev.colorId || '0';
  const key = CFG.COLOR_TO_KEY[colorId];
  if (!key) continue;

  if (key.startsWith('H2') || key === 'H1-Santé' || key === 'H1-Admin') {
    const emoji = CFG.COLORS[key].emoji;
    const dayStr = new Date(ev.start?.dateTime || ev.start?.date)
      .toLocaleDateString('fr-FR', { weekday: 'short', day: 'numeric', timeZone: 'Europe/Paris' });

    weekBlocks.push({
      index: blockIndex++,
      id: ev.id,
      summary: ev.summary || 'Sans titre',
      emoji,
      key,
      dayStr
    });
  }
}

const now = new Date();
const weekNum = Math.ceil((now - new Date(CFG.SAISON.debut)) / (7 * 86400000));

let msg = `📊 <b>BILAN SEMAINE</b>\nSaison 1 — Semaine ${weekNum}/6\n\n`;
msg += `📅 <b>BLOCS PLANIFIÉS CETTE SEMAINE :</b>\n\n`;

const h2 = weekBlocks.filter(b => b.key.startsWith('H2'));
const h1 = weekBlocks.filter(b => b.key.startsWith('H1'));

if (h2.length) {
  msg += '🔵 <b>H2 - Croissance :</b>\n';
  h2.forEach(b => { msg += `  ${b.index}. ${b.emoji} ${b.summary} (${b.dayStr})\n`; });
  msg += '\n';
}
if (h1.length) {
  msg += '⚫ <b>H1 - Socle :</b>\n';
  h1.forEach(b => { msg += `  ${b.index}. ${b.emoji} ${b.summary} (${b.dayStr})\n`; });
  msg += '\n';
}

msg += 'Lesquels as-tu réalisés ?';

state[String(chatId)] = {
  command: 'bilan',
  step: 'check_blocks',
  data: { blocks: weekBlocks, checked: [] },
  updated_at: new Date().toISOString(),
  expires_at: new Date(Date.now() + 7200000).toISOString()
};

const buttons = weekBlocks.map(b => [
  { text: `☐ ${b.index}. ${b.summary.substring(0, 25)}`, callback_data: `bilan_chk|${b.index}` }
]);
buttons.push([{ text: '📊 Voir résultat', callback_data: 'bilan_result' }]);

const replyMarkup = JSON.stringify({ inline_keyboard: buttons });

return [{ json: { chatId, text: msg, parse_mode: 'HTML', replyMarkup } }];

// === CALLBACK HANDLER v2.1 ===
const input = $input.first().json;
const chatId = input.chatId;
const cbd = input.callbackData;
const CFG = input.cfg;
const state = $getWorkflowStaticData('global');
const chatState = state[String(chatId)];

const [action, ...params] = cbd.split('|');

let text = '';
let replyMarkup;
let victoire = null;
let healthLog = null;
let gcalAction = 'none';
let gcalParams = null;

// === VICTOIRE FLOW ===
if (action === 'vic_type') {
  const typeKey = params[0];
  if (chatState) {
    chatState.data.typeKey = typeKey;
    chatState.step = 'ask_horizon';
    chatState.updated_at = new Date().toISOString();
  }
  text = 'Quel horizon ?';
  replyMarkup = JSON.stringify({ inline_keyboard: [
    [
      { text: '⚫ H1', callback_data: 'vic_hz|⚫ H1 Socle' },
      { text: '🔵 H2', callback_data: 'vic_hz|🔵 H2 Croissance' },
      { text: '🟣 H3', callback_data: 'vic_hz|🟣 H3 Passion' }
    ]
  ]});
}

else if (action === 'vic_hz') {
  const horizon = params[0];
  if (chatState) {
    const d = chatState.data;
    const typeKey = d.typeKey;
    const points = CFG.POINTS[typeKey];
    const typeLabel = CFG.POINTS_LABELS[typeKey];

    victoire = {
      title: d.title,
      type: typeLabel,
      horizon: horizon,
      points: points,
      saison: CFG.SAISON.nom
    };

    text = `🎉 <b>+${points} points !</b>\n\n"${d.title}"\n${typeLabel}\n${horizon}`;
    delete state[String(chatId)];
  }
}

// === EVENT FLOW ===
else if (action === 'event_hz') {
  const horizon = params[0];
  const colorCfg = CFG.COLORS[horizon];
  if (chatState) {
    chatState.step = 'ask_title';
    chatState.data.horizon = horizon;
    chatState.data.colorId = colorCfg.id;
    chatState.data.emoji = colorCfg.emoji;
    chatState.data.label = colorCfg.label;
    chatState.data.notionHorizon = colorCfg.horizon;
    chatState.updated_at = new Date().toISOString();
  }
  text = `${colorCfg.emoji} Parfait ! Décris l'événement en une phrase :`;
}

else if (action === 'event_dur') {
  const duration = parseInt(params[0]);
  if (chatState) {
    chatState.step = 'ask_when';
    chatState.data.durationMin = duration;
    chatState.updated_at = new Date().toISOString();
  }
  text = '📅 Quand ? (Tape date et heure, ex: "samedi 9h")';
  replyMarkup = JSON.stringify({ inline_keyboard: [
    [
      { text: 'Demain matin', callback_data: 'event_when|demain_matin' },
      { text: 'Demain soir', callback_data: 'event_when|demain_soir' }
    ],
    [
      { text: 'Samedi 9h', callback_data: 'event_when|samedi_9' },
      { text: 'Dimanche 9h', callback_data: 'event_when|dimanche_9' }
    ]
  ]});
}

else if (action === 'event_when') {
  const whenKey = params[0];
  const now = new Date();
  let targetDate = new Date();

  switch(whenKey) {
    case 'demain_matin':
      targetDate.setDate(now.getDate() + 1);
      targetDate.setHours(9, 0, 0, 0);
      break;
    case 'demain_soir':
      targetDate.setDate(now.getDate() + 1);
      targetDate.setHours(20, 0, 0, 0);
      break;
    case 'samedi_9':
      const daysToSat = (6 - now.getDay() + 7) % 7 || 7;
      targetDate.setDate(now.getDate() + daysToSat);
      targetDate.setHours(9, 0, 0, 0);
      break;
    case 'dimanche_9':
      const daysToSun = (7 - now.getDay()) % 7 || 7;
      targetDate.setDate(now.getDate() + daysToSun);
      targetDate.setHours(9, 0, 0, 0);
      break;
  }

  if (chatState) {
    chatState.data.startTime = targetDate.toISOString();
    const endTime = new Date(targetDate.getTime() + (chatState.data.durationMin || 60) * 60000);
    chatState.data.endTime = endTime.toISOString();
    chatState.updated_at = new Date().toISOString();

    if (chatState.data.horizon === 'H2-Croissance') {
      chatState.step = 'ask_ddf';
      text = '📌 Définition du Fini (DDF) ? Qu\'est-ce qui signifie "terminé" ?\n(Tape ta réponse ou clique Passer)';
      replyMarkup = JSON.stringify({ inline_keyboard: [[{ text: '⏭️ Passer', callback_data: 'event_ddf|skip' }]] });
    } else {
      chatState.step = 'confirm';
      const dateStr = targetDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Paris' });
      const timeStr = targetDate.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris' });
      const d = chatState.data;
      text = `✅ <b>Récapitulatif :</b>\n\n${d.emoji} ${d.label} - ${d.title}\n📅 ${dateStr}, ${timeStr}\n⏱️ ${d.durationMin} min`;
      replyMarkup = JSON.stringify({ inline_keyboard: [
        [{ text: '✅ Confirmer', callback_data: 'event_confirm' }, { text: '❌ Annuler', callback_data: 'event_cancel' }]
      ]});
    }
  }
}

else if (action === 'event_ddf') {
  if (chatState) {
    chatState.data.ddf = params[0] === 'skip' ? '' : params.join('|');
    chatState.step = 'confirm';
    chatState.updated_at = new Date().toISOString();

    const d = chatState.data;
    const dateStr = new Date(d.startTime).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Paris' });
    const timeStr = new Date(d.startTime).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris' });
    text = `✅ <b>Récapitulatif :</b>\n\n${d.emoji} ${d.label} - ${d.title}\n📅 ${dateStr}, ${timeStr}\n⏱️ ${d.durationMin} min`;
    if (d.ddf) text += `\n📌 DDF : ${d.ddf}`;
    replyMarkup = JSON.stringify({ inline_keyboard: [
      [{ text: '✅ Confirmer', callback_data: 'event_confirm' }, { text: '❌ Annuler', callback_data: 'event_cancel' }]
    ]});
  }
}

else if (action === 'event_confirm') {
  if (chatState && chatState.data) {
    const d = chatState.data;
    gcalAction = 'create_event';
    gcalParams = {
      summary: `${d.emoji} ${d.label} - ${d.title}`,
      start: d.startTime,
      end: d.endTime,
      colorId: d.colorId,
      description: d.ddf ? `📌 Objectif : ${d.title}\n📋 DDF : ${d.ddf}` : ''
    };
    text = `🎉 <b>Événement créé dans Google Calendar !</b>\n\n${d.emoji} ${d.label} - ${d.title}`;
    delete state[String(chatId)];
  }
}

else if (action === 'event_cancel') {
  delete state[String(chatId)];
  text = '❌ Création annulée.';
}

// === BILAN FLOW ===
else if (action === 'bilan_chk') {
  const blockIdx = parseInt(params[0]);
  if (chatState && chatState.data) {
    const checked = chatState.data.checked || [];
    const idx = checked.indexOf(blockIdx);
    if (idx >= 0) checked.splice(idx, 1);
    else checked.push(blockIdx);
    chatState.data.checked = checked;
    chatState.updated_at = new Date().toISOString();

    const blocks = chatState.data.blocks || [];
    const buttons = blocks.map(b => {
      const isChecked = checked.includes(b.index);
      return [{ 
        text: `${isChecked ? '☑️' : '☐'} ${b.index}. ${b.summary.substring(0, 25)}`,
        callback_data: `bilan_chk|${b.index}`
      }];
    });
    buttons.push([{ text: '📊 Voir résultat', callback_data: 'bilan_result' }]);

    text = `☑️ ${checked.length} bloc(s) coché(s). Continue ou clique "Voir résultat".`;
    replyMarkup = JSON.stringify({ inline_keyboard: buttons });
  }
}

else if (action === 'bilan_result') {
  if (chatState && chatState.data) {
    const blocks = chatState.data.blocks || [];
    const checked = chatState.data.checked || [];
    const total = blocks.length;
    const done = checked.length;
    const pct = total > 0 ? Math.round((done / total) * 100) : 0;

    const doneBlocks = blocks.filter(b => checked.includes(b.index));
    const missedBlocks = blocks.filter(b => !checked.includes(b.index));

    text = `📊 <b>RÉSULTAT SEMAINE :</b>\n\n`;
    text += `✅ Réalisés : ${done}/${total} (${pct}%)\n`;
    if (missedBlocks.length) {
      text += `❌ Manqués : ${missedBlocks.map(b => b.summary).join(', ')}\n`;
    }

    const h2Done = doneBlocks.filter(b => b.key.startsWith('H2')).length;
    const h2Total = blocks.filter(b => b.key.startsWith('H2')).length;
    const h1Done = doneBlocks.filter(b => b.key.startsWith('H1')).length;
    const h1Total = blocks.filter(b => b.key.startsWith('H1')).length;

    text += `\n🔵 H2 : ${h2Done}/${h2Total} | ⚫ H1 : ${h1Done}/${h1Total}`;

    const weekPoints = doneBlocks.length * 5;
    text += `\n\n🏆 Points semaine : ${weekPoints} pts`;

    text += '\n\n✅ Bilan terminé ! Rappel : Un bloc 🔵 peut être DÉPLACÉ, jamais ANNULÉ. 💪';
    delete state[String(chatId)];
  }
}

// === DONE (marquer événement fait) ===
else if (action === 'done') {
  const eventId = params[0];
  victoire = {
    title: `✅ Bloc terminé`,
    type: '📈 Progrès significatif',
    horizon: '🔵 H2 Croissance',
    points: 5,
    saison: CFG.SAISON.nom
  };
  text = '✅ Bloc marqué comme fait ! +5 pts 🏆';
}

else {
  text = '⚠️ Action non reconnue.';
}

return [{ json: {
  chatId, text, parse_mode: 'HTML', replyMarkup,
  victoire, healthLog, gcalAction, gcalParams,
  callbackQueryId: input.callbackData ? $input.first().json.callbackMessageId : undefined
}}];

// === STATE CONTINUE v2.1 ===
const input = $input.first().json;
const chatId = input.chatId;
const freeText = input.freeText;
const CFG = input.cfg;
const state = $getWorkflowStaticData('global');
const chatState = state[String(chatId)];

if (!chatState) {
  return [{ json: { chatId, text: 'Tape /aide pour voir les commandes disponibles.', parse_mode: 'HTML' } }];
}

const cmd = chatState.command;
const step = chatState.step;
let text = '';
let replyMarkup;
let victoire = null;
let healthLog = null;
let gcalAction = 'none';
let gcalParams = null;

// === EVENT: titre libre ===
if (cmd === 'event' && step === 'ask_title') {
  chatState.data.title = freeText;
  chatState.step = 'ask_duration';
  chatState.updated_at = new Date().toISOString();

  text = '⏰ Durée estimée ?';
  replyMarkup = JSON.stringify({ inline_keyboard: [
    [
      { text: '30 min', callback_data: 'event_dur|30' },
      { text: '1h', callback_data: 'event_dur|60' },
      { text: '1h30', callback_data: 'event_dur|90' },
      { text: '2h', callback_data: 'event_dur|120' }
    ]
  ]});
}

// === EVENT: date libre ===
else if (cmd === 'event' && step === 'ask_when') {
  const now = new Date();
  let targetDate = null;

  const jourMap = {
    'lundi': 1, 'mardi': 2, 'mercredi': 3, 'jeudi': 4,
    'vendredi': 5, 'samedi': 6, 'dimanche': 0,
    'demain': -1, 'aujourd': -2
  };

  const lower = freeText.toLowerCase();
  let jour = null;
  for (const [k, v] of Object.entries(jourMap)) {
    if (lower.includes(k)) { jour = { key: k, val: v }; break; }
  }

  const heureMatch = lower.match(/(\d{1,2})[h:](\d{0,2})/);
  let heure = 9, minutes = 0;
  if (heureMatch) {
    heure = parseInt(heureMatch[1]);
    minutes = heureMatch[2] ? parseInt(heureMatch[2]) : 0;
  }

  if (jour) {
    targetDate = new Date();
    if (jour.val === -1) {
      targetDate.setDate(now.getDate() + 1);
    } else if (jour.val === -2) {
      // aujourd'hui
    } else {
      const currentDay = now.getDay();
      let daysAhead = jour.val - currentDay;
      if (daysAhead <= 0) daysAhead += 7;
      targetDate.setDate(now.getDate() + daysAhead);
    }
    targetDate.setHours(heure, minutes, 0, 0);
  }

  if (targetDate) {
    chatState.data.startTime = targetDate.toISOString();
    const endTime = new Date(targetDate.getTime() + (chatState.data.durationMin || 60) * 60000);
    chatState.data.endTime = endTime.toISOString();
    chatState.updated_at = new Date().toISOString();

    if (chatState.data.horizon === 'H2-Croissance') {
      chatState.step = 'ask_ddf';
      text = '📌 Définition du Fini (DDF) ?\n(Tape ta réponse ou clique Passer)';
      replyMarkup = JSON.stringify({ inline_keyboard: [[{ text: '⏭️ Passer', callback_data: 'event_ddf|skip' }]] });
    } else {
      chatState.step = 'confirm';
      const d = chatState.data;
      const dateStr = targetDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Paris' });
      const timeStr = targetDate.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris' });
      text = `✅ <b>Récapitulatif :</b>\n\n${d.emoji} ${d.label} - ${d.title}\n📅 ${dateStr}, ${timeStr}\n⏱️ ${d.durationMin} min`;
      replyMarkup = JSON.stringify({ inline_keyboard: [
        [{ text: '✅ Confirmer', callback_data: 'event_confirm' }, { text: '❌ Annuler', callback_data: 'event_cancel' }]
      ]});
    }
  } else {
    text = '⚠️ Je n\'ai pas compris la date. Essaie : "samedi 9h", "demain 20h", "lundi 14h30"';
  }
}

// === EVENT: DDF libre ===
else if (cmd === 'event' && step === 'ask_ddf') {
  chatState.data.ddf = freeText;
  chatState.step = 'confirm';
  chatState.updated_at = new Date().toISOString();

  const d = chatState.data;
  const dateStr = new Date(d.startTime).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Paris' });
  const timeStr = new Date(d.startTime).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris' });
  text = `✅ <b>Récapitulatif :</b>\n\n${d.emoji} ${d.label} - ${d.title}\n📅 ${dateStr}, ${timeStr}\n⏱️ ${d.durationMin} min\n📌 DDF : ${d.ddf}`;
  replyMarkup = JSON.stringify({ inline_keyboard: [
    [{ text: '✅ Confirmer', callback_data: 'event_confirm' }, { text: '❌ Annuler', callback_data: 'event_cancel' }]
  ]});
}

// === AUDIT: activité libre ===
else if (cmd === 'audit' && step === 'ask_activity') {
  chatState.data.activity = freeText;
  chatState.step = 'ask_category';
  chatState.updated_at = new Date().toISOString();

  text = `📂 <b>Catégorie ?</b>\n\n(Aide au classement automatique)`;
  replyMarkup = JSON.stringify({ inline_keyboard: [
    [
      { text: '🟢 Santé', callback_data: 'audit_cat|sante' },
      { text: '⚫ Finance/Admin', callback_data: 'audit_cat|admin' },
      { text: '🟡 Famille', callback_data: 'audit_cat|famille' }
    ],
    [
      { text: '🔴 Travail', callback_data: 'audit_cat|travail' },
      { text: '🔵 Projet perso', callback_data: 'audit_cat|projet' },
      { text: '🟣 Loisir/Tech', callback_data: 'audit_cat|loisir' }
    ]
  ]});
}

else {
  text = '⚠️ Commande expirée ou non reconnue. Tape /aide.';
  delete state[String(chatId)];
}

return [{ json: { chatId, text, parse_mode: 'HTML', replyMarkup, victoire, healthLog, gcalAction, gcalParams } }];

// === UNKNOWN COMMAND / TEXT ===
const chatId = $input.first().json.chatId;
const text = '🤔 Commande non reconnue. Tape /aide pour voir les commandes disponibles.';
return [{ json: { chatId, text, parse_mode: 'HTML' } }];
